-- ============================================================
-- F5 Hands-On Lab: Insert Account Data
-- ============================================================
-- ~200 Fortune 500 accounts, USA-based, spread across timezones
-- Run as SYSADMIN after 02_create_tables.sql
-- ============================================================

USE ROLE SYSADMIN;
USE WAREHOUSE COMPUTE_WH;
USE DATABASE F5_PROD;
USE SCHEMA RAW;

INSERT INTO DIM_CUST_ACCT_SFDC (
    DIM_CUST_ACCT_SFDC_KEY, SFDCF5_ACCT_ID, ACCT_NAME, ACCT_TYPE_CODE,
    ACCT_STATUS_CODE, INDUSTRY_NAME, INDUSTRY_GROUPING_CODE,
    ANNUAL_REVENUE_AMT, EMPLOYEE_CNT, BILLING_CITY_NAME,
    BILLING_STATE_PROVINCE_NAME, BILLING_COUNTRY_NAME,
    THEATER_NAME, THEATER_CODE, ETM_REGION_NAME, FORTUNE_1000_RANK_NUM,
    TICKER_SYMBOL_CODE, WEBSITE_URL_TEXT
)
SELECT
    MD5(col1) AS DIM_CUST_ACCT_SFDC_KEY,
    col1 AS SFDCF5_ACCT_ID,
    col2 AS ACCT_NAME,
    'Customer' AS ACCT_TYPE_CODE,
    'Active' AS ACCT_STATUS_CODE,
    col3 AS INDUSTRY_NAME,
    col4 AS INDUSTRY_GROUPING_CODE,
    col5 AS ANNUAL_REVENUE_AMT,
    col6 AS EMPLOYEE_CNT,
    col7 AS BILLING_CITY_NAME,
    col8 AS BILLING_STATE_PROVINCE_NAME,
    'United States' AS BILLING_COUNTRY_NAME,
    'Americas' AS THEATER_NAME,
    'AMER' AS THEATER_CODE,
    col9 AS ETM_REGION_NAME,
    col10 AS FORTUNE_1000_RANK_NUM,
    col11 AS TICKER_SYMBOL_CODE,
    col12 AS WEBSITE_URL_TEXT
FROM VALUES
