-- Update territory codes based on region
UPDATE DIM_CUST_ACCT_SFDC
SET ETM_TERRITORY_CODE = 'AMER-' || ETM_REGION_NAME || '-' || LPAD(ABS(HASH(SFDCF5_ACCT_ID)) % 5 + 1, 3, '0'),
    ETM_TERRITORY_NAME = ETM_REGION_NAME || ' Territory ' || (ABS(HASH(SFDCF5_ACCT_ID)) % 5 + 1),
    VARICENT_TERRITORY_CODE = 'VTC-' || ETM_REGION_NAME || '-' || LPAD(ABS(HASH(SFDCF5_ACCT_ID)) % 5 + 1, 3, '0');

-- Verify
SELECT ETM_REGION_NAME, COUNT(*) AS account_count
FROM DIM_CUST_ACCT_SFDC
GROUP BY 1
ORDER BY 2 DESC;
